insert into public.news (day,month,source,title,body,published,sort) values
('02','{"en":"JUL","fr":"JUIL","es":"JUL"}'::jsonb,'{"en":"IYRP / FAO","fr":"IYRP / FAO","es":"IYRP / FAO"}'::jsonb,'{"en":"IYRP 2026: regional rangelands consultations continue across the Sahel","fr":"IYRP 2026 : les consultations régionales sur les parcours se poursuivent au Sahel","es":"IYRP 2026: continúan las consultas regionales sobre pastizales en el Sahel"}'::jsonb,'{"en":"The International Year of Rangelands and Pastoralists mobilizes pastoral networks around mobility rights and land tenure.","fr":"L''Année internationale des parcours et des pasteurs mobilise les réseaux pastoraux autour des droits de mobilité et du foncier.","es":"El Año Internacional de los Pastizales moviliza a las redes pastoriles en torno a la movilidad y la tenencia de tierras."}'::jsonb,true,0),
('24','{"en":"JUN","fr":"JUIN","es":"JUN"}'::jsonb,'{"en":"Academic review","fr":"Revue académique","es":"Revista académica"}'::jsonb,'{"en":"Green transition and pastoral lands: new research maps land-acquisition pressures","fr":"Transition verte et terres pastorales : de nouvelles recherches cartographient les pressions foncières","es":"Transición verde y tierras pastoriles: nuevas investigaciones mapean las presiones sobre la tierra"}'::jsonb,'{"en":"Peer-reviewed work documents how renewable-energy projects overlap customary pastoral territories.","fr":"Des travaux évalués par les pairs documentent le chevauchement entre projets d''énergies renouvelables et territoires pastoraux coutumiers.","es":"Trabajos revisados por pares documentan la superposición de proyectos de energía renovable con territorios pastoriles consuetudinarios."}'::jsonb,true,1),
('15','{"en":"JUN","fr":"JUIN","es":"JUN"}'::jsonb,'{"en":"UN DESA","fr":"UN DESA","es":"UN DESA"}'::jsonb,'{"en":"UNPFII follow-up: recommendations on indigenous data governance","fr":"Suivi de l''UNPFII : recommandations sur la gouvernance des données autochtones","es":"Seguimiento del UNPFII: recomendaciones sobre gobernanza de datos indígenas"}'::jsonb,'{"en":"The Permanent Forum reiterates support for CARE principles in national statistics and research.","fr":"L''Instance permanente réitère son soutien aux principes CARE dans les statistiques nationales et la recherche.","es":"El Foro Permanente reitera su apoyo a los principios CARE en las estadísticas nacionales y la investigación."}'::jsonb,true,2);
